mapper.select:
SELECT id as id, dealerId as dealerId, (select dealerName from dealer where id = dealerId) as dealerName, activityTypeId as activityTypeId, (select activityType from activity_config where id = activityTypeId) as activityType, activityTime as activityTime, applyFee as applyFee, writeOffStatus as writeOffStatus, activityContent as activityContent FROM activity_info
1=1
AND id = #{id}
AND dealerId
AND activityType = #{activityType}
ORDER BY id DESC
